var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"좌표도, 방향도 틀림없는데……","JPN":"座標も、方向も間違いないのに……","ENG":"The directions and the coordinates should be correct...","TWN":"座標、方向也都沒錯……"},"stage":{"bg":"CRUISE","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"루나, 뭐 좀 보이나요?","JPN":"ルナさん、何か見えますか？","ENG":"Luna, do you see anything?","TWN":"露娜，看見什麼了嗎？"},"stage":{"bg":"CRUISE","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"어디를 봐도 새하얀 구름에 시퍼런 바다뿐이야.","JPN":"どこを見ても真っ白な雲に真っ青な海だけだよ。","ENG":"Everywhere I look, it's all white clouds on top and blue water below.","TWN":"不管怎麼看，都是潔白的雲彩和蔚藍的大海。"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"지도에는 없는 섬이라니, 혹시 우리 그 할배한테 깜빡 속은 거 아냐?","JPN":"地図にはない島って。もしかしてアタシたち、あのジジイに騙されたんじゃない？","ENG":"An island that's not on the map... Did that geezer trick us?","TWN":"地圖上不存在的小島，我們不會被那個老爺爺給騙了吧？"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"위치는 제대로 말해 줬네만, 배를 모는 기술은 다른 문제지.","JPN":"位置はしっかりと教えてくれても、船を操る技術はまた別の問題さ。","ENG":"He gave us the right coordinates, but perhaps it's more about our ability to sail.","TWN":"位置已經說清楚了，但開船的技術就另當別論了。"},"stage":{"bg":"CRUISE","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"맥크레디 양이 나침반을 잘못 보는 순간 우리 모두 표류자 신세가 될 수도 있다네.","JPN":"マクレディー君がコンパスを見間違えた瞬間、我々全員が漂流者になり得る。","ENG":"We'll all be castaways the moment Regina misreads the compass.","TWN":"如果麥克蕾蒂看錯指南針，我們可能就都得隨波漂流了。"},"stage":{"bg":"CRUISE","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"그, 그럼 저희 모두 전설 속 유령선처럼 백골이 된 뒤에도 영원히 바다를 떠도는 건가요?","JPN":"そ、それじゃ私たちはみんな、伝説の中の幽霊船のように白骨になっても永遠に海を彷徨うんですか？","ENG":"D-does that mean we'll end up like the ghosts from legends that wander the sea for eternity?","TWN":"那裂隙那我們會像傳說中的幽靈船一樣，變成白骨後還永遠在海上漂泊嗎？"},"stage":{"bg":"CRUISE","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"괜한 소리에 무서워하지 마세요, 실키.","JPN":"ばかばかしい話に怖がらないでください、シルキー。","ENG":"Do not get scared by his words, Sylkie.","TWN":"你別聽他胡說，思琪。"},"stage":{"bg":"CRUISE","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그리고 유령선은 대항해시대 때 무풍지대에서 조난당한 범선들에서 기원한 이야기입니다.","JPN":"それに、幽霊船は大航海時代に無風地帯で遭難した帆船から始まった物語ですわ。","ENG":"Also, ghost ship stories originated from ships that became stranded in the Sargasso Sea during the Age of Discovery.","TWN":"還有，幽靈船的故事起源於大航海時代在無風地帶遇難的船隻。"},"stage":{"bg":"CRUISE","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"동력기관으로 항해할 수 있는 현대의 배에는 통용되지 않아요.","JPN":"動力機関で航海する現代の船には通用しません。","ENG":"The phrase is therefore no longer relevant given the engines of modern ships.","TWN":"不適用於可以用動力機械航行的現代船隻。"},"stage":{"bg":"CRUISE","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"그렇군요……","JPN":"そうなんですね……","ENG":"I see...","TWN":"這樣啊……"},"stage":{"bg":"CRUISE","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"하지만 죽은 뒤에도 부학회장님을 모실 수 있다면, 그것도 나쁘지 않을 것 같아요.","JPN":"でも死んだ後も副学会長様に仕えられるなら、それも悪くないと思います。","ENG":"But if I can still be your caregiver in the afterlife, I don't think it'll be that bad.","TWN":"不過如果死了以後也能服侍副學會長的話，那好像也不錯。"},"stage":{"bg":"CRUISE","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"어…… 우선 죽지 않을 생각부터 해 주시겠어요?","JPN":"えーっと……まずは死なないことから考えてくれますか？","ENG":"Uh... How about we consider not dying first?","TWN":"呃……你可以先想想怎樣能不死嗎？"},"stage":{"bg":"CRUISE","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"앗, 부학회장! 북쪽에 뭔가 보여!","JPN":"あっ、副学会長！　北の方に何か見える！","ENG":"Oh! Vice President! I see something up north!","TWN":"啊，副學會長！北邊有什麼東西！"},"stage":{"bg":"CRUISE","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"배는 아닌 것 같은데…… 정말 섬인가?","JPN":"船じゃないみたいだけど……本当に島なのかな？","ENG":"It's not a boat... Is it really an island?","TWN":"好像不是船……真的是小島嗎？"},"stage":{"bg":"CRUISE","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"확인해 볼 가치는 있겠네요. 우선 갑판으로 돌아오세요.","JPN":"確認してみる価値はありそうですわね。まずはデッキに戻ってください。","ENG":"It might be worth checking out. Come back down to the deck.","TWN":"值得確認一下。先回到甲板上來吧。"},"stage":{"bg":"CRUISE","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"기관의 본거지라니…… 각오를 단단히 해야겠네요.","JPN":"機関の本拠地……しっかり覚悟しないとダメですね。","ENG":"The headquarters of the Institution... I guess we should brace ourselves.","TWN":"機關的大本營……看來要做好心理準備了。"},"stage":{"bg":"CRUISE","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SERIOUS"}}}}]`);export{e as default};